INSERT INTO toeic_listening_part2
  (position, category, question, options, answer, question_audio_url, option_audio_urls, is_exam, dataset_id)
VALUES
  (1, 'requests_suggestions', 'Could you help me move this desk to the corner?', '["(A) It''s a very nice desk.", "(B) Move it to the left.", "(C) Sure, I''d be happy to."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q01_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q01_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q01_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q01_C.mp3"}', true, NULL),
  (2, 'requests_suggestions', 'Why don''t we grab a coffee before the meeting starts?', '["(A) I just had one, but thanks.", "(B) Two sugars, please.", "(C) In the conference room."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q02_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q02_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q02_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q02_C.mp3"}', true, NULL),
  (3, 'requests_suggestions', 'Would you mind checking these figures for me?', '["(A) About fifteen percent.", "(B) No, not at all.", "(C) The check is in the mail."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q03_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q03_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q03_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q03_C.mp3"}', true, NULL),
  (4, 'requests_suggestions', 'Could you tell me where the nearest post office is?', '["(A) At three o''clock.", "(B) To mail a package.", "(C) I''m sorry, I''m not from around here."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q04_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q04_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q04_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q04_C.mp3"}', true, NULL),
  (5, 'requests_suggestions', 'Why don''t we take a taxi instead of the bus?', '["(A) That sounds like a faster option.", "(B) The bus stop is over there.", "(C) No, I haven''t seen it."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q05_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q05_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q05_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q05_C.mp3"}', true, NULL),
  (6, 'requests_suggestions', 'Would you like to join us for dinner tonight?', '["(A) I had a steak.", "(B) I''m afraid I have other plans.", "(C) The restaurant is open."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q06_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q06_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q06_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q06_C.mp3"}', true, NULL),
  (7, 'requests_suggestions', 'Could you lower the volume of the radio?', '["(A) Yes, I''ll turn it down right away.", "(B) It''s a new station.", "(C) I turned it on."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q07_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q07_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q07_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q07_C.mp3"}', true, NULL),
