  (74, 'why_how', 'How can we reduce our energy consumption this month?', '["(A) By turning off lights in empty rooms.", "(B) The electric bill was very high.", "(C) It''s a renewable energy source."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q74_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q74_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q74_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q74_C.mp3"}', true, NULL),
  (75, 'why_how', 'Why is the ventilation system making that loud noise?', '["(A) I''ll call the maintenance crew to check it.", "(B) No, it isn''t very loud in here.", "(C) It was installed last summer."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q75_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q75_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q75_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q75_C.mp3"}', true, NULL),
  (76, 'why_how', 'How did you hear about the job opening at our firm?', '["(A) I''ve worked here for five years.", "(B) I saw the advertisement on a professional network.", "(C) The opening ceremony was lovely."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q76_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q76_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q76_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q76_C.mp3"}', true, NULL),
  (77, 'why_how', 'Why wasn''t the budget proposal approved?', '["(A) We need to provide more cost details.", "(B) It''s in the blue folder on your desk.", "(C) I''ll approve it later today."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q77_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q77_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q77_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q77_C.mp3"}', true, NULL),
  (78, 'why_how', 'How long does it take to process a travel reimbursement?', '["(A) About two weeks from the date of submission.", "(B) It was a very expensive trip.", "(C) To the accounting department."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q78_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q78_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q78_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q78_C.mp3"}', true, NULL),
  (79, 'why_how', 'Why are the streetlights still on at noon?', '["(A) There must be a timer malfunction.", "(B) The street is being repaved.", "(C) Because the sensor is likely broken."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q79_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q79_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q79_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q79_C.mp3"}', true, NULL),
  (80, 'why_how', 'How many more copies of the agenda do we need?', '["(A) I already read the agenda.", "(B) Just five more should be enough.", "(C) The meeting is at noon."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q80_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q80_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q80_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q80_C.mp3"}', true, NULL),
  (81, 'yes_no', 'Do you have the latest sales report?', '["(A) No, I''m still working on it.", "(B) Yes, it''s a very long report.", "(C) He reports to the manager."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q81_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q81_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q81_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q81_C.mp3"}', true, NULL),
  (82, 'yes_no', 'Is the conference room available at three?', '["(A) Yes, there are three rooms.", "(B) No, it''s booked until four.", "(C) Yes, the conference was great."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q82_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q82_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q82_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q82_C.mp3"}', true, NULL),
  (83, 'yes_no', 'Are you joining us for lunch today?', '["(A) The lunch menu is on the table.", "(B) It''s a very nice restaurant.", "(C) I ate at my desk already."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q83_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q83_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q83_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q83_C.mp3"}', true, NULL),
  (84, 'yes_no', 'Have you met the new intern yet?', '["(A) Yes, he seems very bright.", "(B) The meeting is in Room 2.", "(C) No, I haven''t seen the movie."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q84_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q84_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q84_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q84_C.mp3"}', true, NULL),
  (85, 'yes_no', 'Does this bus go to the airport?', '["(A) Yes, take your car.", "(B) The airport is very modern.", "(C) Yes, but you need to transfer."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q85_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q85_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q85_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q85_C.mp3"}', true, NULL),
  (86, 'yes_no', 'Is Mr. Kim in his office right now?', '["(A) He''ll be back in ten minutes.", "(B) It''s a very large office.", "(C) Yes, he is Kim."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q86_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q86_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q86_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q86_C.mp3"}', true, NULL),
  (87, 'yes_no', 'Are these files ready for the meeting?', '["(A) I''ll meet you there.", "(B) They still need to be signed.", "(C) The filing cabinet is over there."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q87_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q87_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q87_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q87_C.mp3"}', true, NULL),
  (88, 'yes_no', 'Have the invitations been sent out?', '["(A) No, I wasn''t invited.", "(B) They''ve been sent to the grand ballroom.", "(C) I mailed them this morning."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q88_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q88_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q88_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q88_C.mp3"}', true, NULL),
  (89, 'yes_no', 'Do we need to bring anything to the workshop?', '["(A) Just a notepad and a pen.", "(B) The workshop was very helpful.", "(C) No, I don''t need it."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q89_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q89_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q89_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q89_C.mp3"}', true, NULL),
  (90, 'yes_no', 'Is there a pharmacy near the hotel?', '["(A) I stayed there last year.", "(B) It''s right around the corner.", "(C) The medicine is expensive."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q90_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q90_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q90_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q90_C.mp3"}', true, NULL),
  (91, 'yes_no', 'Are you finished with the photocopier?', '["(A) It''s a color copier.", "(B) Yes, about twenty copies.", "(C) Of course, you can use it now."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q91_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q91_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q91_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q91_C.mp3"}', true, NULL),
  (92, 'yes_no', 'Has the mail been delivered yet?', '["(A) To the post office.", "(B) Not yet, it usually comes later.", "(C) I''ll mail it for you."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q92_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q92_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q92_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q92_C.mp3"}', true, NULL),
  (93, 'yes_no', 'Do you know where the nearest bank is?', '["(A) It''s next to the supermarket.", "(B) No, I don''t have an account.", "(C) I need to withdraw some money."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q93_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q93_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q93_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q93_C.mp3"}', true, NULL),
  (94, 'yes_no', 'Is the project deadline still Friday?', '["(A) I enjoyed the project.", "(B) Yes, Friday is a holiday.", "(C) No, it''s been moved to Monday."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q94_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q94_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q94_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q94_C.mp3"}', true, NULL),
  (95, 'yes_no', 'Are the technicians coming today?', '["(A) They''re scheduled for tomorrow.", "(B) The technical manual is here.", "(C) Yes, I''m a technician."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q95_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q95_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q95_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q95_C.mp3"}', true, NULL),
  (96, 'yes_no', 'Have you seen my car keys?', '["(A) The car is in the garage.", "(B) I think they''re on your desk.", "(C) Yes, I can drive."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q96_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q96_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q96_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q96_C.mp3"}', true, NULL),
  (97, 'yes_no', 'Does the price include breakfast?', '["(A) It''s served from 7 to 10.", "(B) No, that''s an additional charge.", "(C) I''d like some eggs, please."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q97_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q97_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q97_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q97_C.mp3"}', true, NULL),
  (98, 'yes_no', 'Is this seat taken?', '["(A) I took the bus.", "(B) Yes, it''s a very comfortable chair.", "(C) No, please go ahead and sit."]', 'C', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q98_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q98_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q98_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q98_C.mp3"}', true, NULL),
  (99, 'yes_no', 'Are you traveling for business or pleasure?', '["(A) I''ll be there for a week.", "(B) Mostly for business.", "(C) Yes, I like traveling."]', 'B', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q99_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q99_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q99_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q99_C.mp3"}', true, NULL),
  (100, 'yes_no', 'Has everyone signed the attendance sheet?', '["(A) No, Sarah hasn''t signed it yet.", "(B) The flight was on time.", "(C) I''ll attend the meeting."]', 'A', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q100_question.mp3', '{"A": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q100_A.mp3", "B": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q100_B.mp3", "C": "https://storage.googleapis.com/choppetonexam_toeic/toeic/part2/audio/q100_C.mp3"}', true, NULL);
INSERT INTO toeic_listening_part3
  (position, dialogue, questions, audio_url, is_exam, dataset_id)
VALUES
  (1, '[{"speaker": "F", "text": "I''m looking for the lecture hall for the \"Digital Trends\" seminar."}, {"speaker": "M", "text": "That was moved to the annex building because the original room had a leak in the ceiling."}, {"speaker": "F", "text": "Oh, thank you. I''d better hurry; it starts in five minutes and I don''t want to miss the intro."}]', '[{"text": "What event is the woman attending?", "options": ["(A) A building inspection", "(B) A plumbing workshop", "(C) A technology seminar", "(D) A graduation ceremony"], "answer": "C"}, {"text": "What is the problem with the original room?", "options": ["(A) It was too small", "(B) It was too far away", "(C) It was double-booked", "(D) It has water damage"], "answer": "D"}, {"text": "Where is the event now located?", "options": ["(A) In the main lobby", "(B) On the roof", "(C) In a separate building", "(D) In the basement"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv02.mp3', true, NULL),
  (2, '[{"speaker": "F", "text": "I''m calling because the air conditioning in my room is making a very loud noise."}, {"speaker": "M", "text": "I''m sorry about that, Mrs. Lee. I''ll send a maintenance worker up to room 405 immediately."}, {"speaker": "F", "text": "Thank you. I have a conference call in 30 minutes, so I hope it can be fixed quickly."}]', '[{"text": "Why is the woman calling?", "options": ["(A) To book a room", "(B) To order room service", "(C) To report a problem", "(D) To check out early"], "answer": "C"}, {"text": "Where is the woman located?", "options": ["(A) In the lobby", "(B) In room 305", "(C) In the restaurant", "(D) In room 405"], "answer": "D"}, {"text": "What is the woman''s deadline?", "options": ["(A) She is leaving for the airport", "(B) She has a scheduled call", "(C) She has a dinner reservation", "(D) She needs to sleep"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv20.mp3', true, NULL),
  (3, '[{"speaker": "F", "text": "Have you seen the new employee directory? They finally added the photos."}, {"speaker": "M", "text": "Not yet. Does it include the interns who started last week?"}, {"speaker": "F", "text": "Yes, everyone is in there. It makes it much easier to recognize people from other departments."}]', '[{"text": "What was recently added to the directory?", "options": ["(A) Phone numbers", "(B) Email addresses", "(C) Job titles", "(D) Pictures"], "answer": "D"}, {"text": "Who started working last week?", "options": ["(A) The CEO", "(B) The sales team", "(C) Temporary staff", "(D) The manager"], "answer": "C"}, {"text": "What is the benefit of the update?", "options": ["(A) Faster communication", "(B) Identifying coworkers", "(C) Better security", "(D) Easier payroll"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv49.mp3', true, NULL),
  (4, '[{"speaker": "F", "text": "My flight to Seoul departs at 10:00 AM, but I haven''t received my digital boarding pass yet."}, {"speaker": "M", "text": "You can print a physical one at the self-service kiosk near the check-in counter."}, {"speaker": "F", "text": "Oh, that''s a relief. I was worried I would have to wait in the long line at the desk."}]', '[{"text": "Where is the woman going?", "options": ["(A) Tokyo", "(B) Beijing", "(C) Seoul", "(D) Bangkok"], "answer": "C"}, {"text": "What is the woman''s problem?", "options": ["(A) Her flight is delayed", "(B) She lost her passport", "(C) She lacks a travel document", "(D) She missed her boarding time"], "answer": "C"}, {"text": "Where can the woman get her pass?", "options": ["(A) At the security gate", "(B) From a flight attendant", "(C) At an automated machine", "(D) In the lounge"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv16.mp3', true, NULL),
  (5, '[{"speaker": "M", "text": "I''d like to sign up for the advanced accounting seminar."}, {"speaker": "F", "text": "You''ll need to provide proof that you''ve completed the introductory course first."}, {"speaker": "M", "text": "I have my certificate from last year right here in my bag."}]', '[{"text": "What does the man want to do?", "options": ["(A) Teach a class", "(B) Get a job", "(C) Join a seminar", "(D) Pay a bill"], "answer": "C"}, {"text": "What is a requirement for the seminar?", "options": ["(A) A high fee", "(B) A letter of intent", "(C) A previous course", "(D) Five years of experience"], "answer": "C"}, {"text": "What does the man have with him?", "options": ["(A) A resume", "(B) A check", "(C) A textbook", "(D) A certificate"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv50.mp3', true, NULL),
  (6, '[{"speaker": "M", "text": "Our visitor from the London branch, Mr. Sterling, will be here at 2:00 PM today."}, {"speaker": "F", "text": "Should I book a table for four at the bistro across the street for an early dinner?"}, {"speaker": "M", "text": "Actually, he''s coming straight from the airport and requested a light lunch instead."}]', '[{"text": "Who is arriving at 2:00 PM?", "options": ["(A) A new client", "(B) A local manager", "(C) An international colleague", "(D) A delivery driver"], "answer": "C"}, {"text": "What did the woman suggest doing?", "options": ["(A) Booking a hotel", "(B) Giving a tour", "(C) Organizing a dinner", "(D) Canceling a meeting"], "answer": "C"}, {"text": "What does the guest prefer?", "options": ["(A) A heavy meal", "(B) A late snack", "(C) A morning coffee", "(D) A midday meal"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv40.mp3', true, NULL),
  (7, '[{"speaker": "M", "text": "I''m looking for a gift for my wife. It''s our tenth wedding anniversary."}, {"speaker": "F", "text": "Congratulations! How about a silver necklace? It''s a traditional gift for that milestone."}, {"speaker": "M", "text": "That''s a wonderful idea. Do you have any with a sapphire stone? That''s her favorite color."}]', '[{"text": "What is the man celebrating?", "options": ["(A) A birthday", "(B) A promotion", "(C) An anniversary", "(D) A retirement"], "answer": "C"}, {"text": "What does the woman recommend?", "options": ["(A) A watch", "(B) A ring", "(C) A piece of jewelry", "(D) A silver frame"], "answer": "C"}, {"text": "What detail does the man provide about his wife?", "options": ["(A) Her dress size", "(B) Her favorite flower", "(C) Her preferred gemstone", "(D) Her favorite brand"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv19.mp3', true, NULL),
  (8, '[{"speaker": "F", "text": "We need to find a new venue for the holiday party. The hotel we usually use is undergoing renovations."}, {"speaker": "M", "text": "How about the community center? It has a large hall and a professional kitchen."}, {"speaker": "F", "text": "That''s a good idea. I''ll call them this afternoon to check the availability for December 15th."}]', '[{"text": "What is the problem with the usual hotel?", "options": ["(A) It is too expensive", "(B) It is being repaired", "(C) It is fully booked", "(D) It is too small"], "answer": "B"}, {"text": "What does the man suggest?", "options": ["(A) Canceling the party", "(B) A different location", "(C) Changing the date", "(D) Hiring a decorator"], "answer": "B"}, {"text": "When does the woman want to hold the event?", "options": ["(A) November 15th", "(B) December 1st", "(C) December 15th", "(D) January 1st"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv32.mp3', true, NULL),
  (9, '[{"speaker": "F", "text": "The printer on the fourth floor is out of paper again."}, {"speaker": "M", "text": "I just checked the supply room, but we''re completely out. The new shipment won''t arrive until tomorrow."}, {"speaker": "F", "text": "I guess I''ll have to use the printer in the basement for now."}]', '[{"text": "What is the issue?", "options": ["(A) The printer is jammed", "(B) The ink is empty", "(C) Lack of paper", "(D) The printer is slow"], "answer": "C"}, {"text": "When will the new supplies arrive?", "options": ["(A) Today", "(B) Tomorrow", "(C) Next week", "(D) In two days"], "answer": "B"}, {"text": "Where will the woman go to print her work?", "options": ["(A) The fourth floor", "(B) The lobby", "(C) The basement", "(D) Across the street"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv47.mp3', true, NULL),
  (10, '[{"speaker": "M", "text": "The annual staff picnic is scheduled for this Saturday, but the weather forecast says it''s going to rain."}, {"speaker": "F", "text": "Should we move it to the following weekend, or just hold it in the company cafeteria?"}, {"speaker": "M", "text": "Let''s move it to next Saturday. People would prefer to be outside at the park."}]', '[{"text": "What event is being discussed?", "options": ["(A) A business meeting", "(B) A holiday party", "(C) A staff picnic", "(D) A retirement lunch"], "answer": "C"}, {"text": "What is the problem with the original plan?", "options": ["(A) Not enough people signed up", "(B) The park is closed", "(C) The budget was cut", "(D) Likely bad weather"], "answer": "D"}, {"text": "What did the man decide?", "options": ["(A) To cancel the event", "(B) To have it in the cafeteria", "(C) To change the date", "(D) To buy umbrellas for everyone"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv27.mp3', true, NULL),
  (11, '[{"speaker": "F", "text": "Excuse me, I''m here for the 2:00 PM job interview with the human resources manager."}, {"speaker": "M", "text": "Ah, yes. Mr. Thompson is expecting you. Please sign the visitor log and take a seat."}, {"speaker": "F", "text": "Thank you. Should I leave my coat here, or should I take it with me?"}]', '[{"text": "Why is the woman at the office?", "options": ["(A) To deliver a package", "(B) To meet a client", "(C) To fix a computer", "(D) To apply for a position"], "answer": "D"}, {"text": "Who is the woman meeting with?", "options": ["(A) The CEO", "(B) A security guard", "(C) An HR manager", "(D) A sales representative"], "answer": "C"}, {"text": "What is the woman asked to do?", "options": ["(A) Wait outside", "(B) Call Mr. Thompson", "(C) Provide her signature", "(D) Show her identification"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv12.mp3', true, NULL),
  (12, '[{"speaker": "F", "text": "My car is in the shop, so I''ll be taking the train to work for the next few days."}, {"speaker": "M", "text": "You should buy a weekly pass; it''s much cheaper than buying individual tickets every day."}, {"speaker": "F", "text": "I''ll check the price at the station. Hopefully, the commute isn''t too long."}]', '[{"text": "Why is the woman using public transportation?", "options": ["(A) She sold her car", "(B) She wants to save money", "(C) Her car is being fixed", "(D) She lost her license"], "answer": "C"}, {"text": "What does the man recommend?", "options": ["(A) Walking to work", "(B) A carpool", "(C) A multi-day ticket", "(D) A different route"], "answer": "C"}, {"text": "Where will the woman get more information?", "options": ["(A) Online", "(B) From her boss", "(C) At the office", "(D) At the transit hub"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv43.mp3', true, NULL),
  (13, '[{"speaker": "M", "text": "I''d like to order a large pepperoni pizza for delivery, please."}, {"speaker": "F", "text": "Certainly. That will be $18.50. What is your address?"}, {"speaker": "M", "text": "I''m at 422 West Oak Street, Apartment 3B. How long will it take?"}]', '[{"text": "What is the man doing?", "options": ["(A) Renting an apartment", "(B) Ordering food", "(C) Complaining about a price", "(D) Reserving a table"], "answer": "B"}, {"text": "How much will the man pay?", "options": ["(A) $3.00", "(B) $4.22", "(C) $15.00", "(D) $18.50"], "answer": "D"}, {"text": "Where is the man located?", "options": ["(A) In a hotel", "(B) In a restaurant", "(C) In an apartment", "(D) In a shopping mall"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv03.mp3', true, NULL),
  (14, '[{"speaker": "M", "text": "We need to find a new caterer for the annual awards banquet in October."}, {"speaker": "F", "text": "I agree. The food from the Italian place we used last year was a bit too salty for most guests."}, {"speaker": "M", "text": "What about that new French bistro on Main Street? I''ve heard their service is excellent."}]', '[{"text": "What event are the speakers planning?", "options": ["(A) A retirement party", "(B) A holiday lunch", "(C) A wedding reception", "(D) An awards ceremony"], "answer": "D"}, {"text": "What was the problem last year?", "options": ["(A) The food arrived late", "(B) The price was too high", "(C) The meal quality was poor", "(D) The venue was too small"], "answer": "C"}, {"text": "What does the man suggest?", "options": ["(A) Cooking the food themselves", "(B) Postponing the banquet", "(C) Trying a different restaurant", "(D) Changing the menu items"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv13.mp3', true, NULL),
  (15, '[{"speaker": "M", "text": "I''m having trouble logging into the company portal. My password keeps getting rejected."}, {"speaker": "F", "text": "The system was updated last night. Everyone has to reset their credentials this morning."}, {"speaker": "M", "text": "Oh, I didn''t see the email about that. I''ll go ahead and create a new one now."}]', '[{"text": "What is the man''s issue?", "options": ["(A) Accessing a website", "(B) Finding a document", "(C) Sending an email", "(D) Fixing a printer"], "answer": "A"}, {"text": "What happened last night?", "options": ["(A) A power outage", "(B) A system update", "(C) A security breach", "(D) A software crash"], "answer": "B"}, {"text": "What will the man do next?", "options": ["(A) Call IT support", "(B) Wait for an email", "(C) Change his password", "(D) Restart his computer"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv33.mp3', true, NULL),
  (16, '[{"speaker": "F", "text": "I need to renew my passport before my trip to Italy in three months."}, {"speaker": "M", "text": "You should do it soon. The processing time has increased to eight weeks lately."}, {"speaker": "F", "text": "I''ll go to the post office this Friday to submit the application."}]', '[{"text": "Where is the woman planning to go?", "options": ["(A) France", "(B) Spain", "(C) Italy", "(D) Greece"], "answer": "C"}, {"text": "What does the man say about the passport process?", "options": ["(A) It is very expensive", "(B) It is now online only", "(C) It is faster than before", "(D) It takes longer now"], "answer": "D"}, {"text": "When will the woman submit her paperwork?", "options": ["(A) Today", "(B) Tomorrow", "(C) This Friday", "(D) Next month"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv45.mp3', true, NULL),
  (17, '[{"speaker": "F", "text": "Can you tell me which platform the express train to London leaves from?"}, {"speaker": "M", "text": "That''s platform 9, but it''s delayed by 20 minutes due to signal problems."}, {"speaker": "F", "text": "Oh, that''s frustrating. Is there a coffee shop nearby where I can wait?"}]', '[{"text": "Where is this conversation taking place?", "options": ["(A) An airport", "(B) A train station", "(C) A bus stop", "(D) A coffee shop"], "answer": "B"}, {"text": "Why is the train delayed?", "options": ["(A) Bad weather", "(B) Staff shortages", "(C) A medical emergency", "(D) Technical issues"], "answer": "D"}, {"text": "What does the woman want to find?", "options": ["(A) A ticket office", "(B) Platform 9", "(C) A place to get a drink", "(D) A luggage locker"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv07.mp3', true, NULL),
  (18, '[{"speaker": "M", "text": "Excuse me, I''m looking for the \"Contemporary Art\" exhibit. Is it on this floor?"}, {"speaker": "F", "text": "No, it''s actually in the new gallery wing on the third floor. You can take the stairs or the elevator behind the gift shop."}, {"speaker": "M", "text": "Great, thanks. Does my general admission ticket cover that exhibit, or is there an extra fee?"}]', '[{"text": "Where most likely are the speakers?", "options": ["(A) A shopping mall", "(B) A movie theater", "(C) A museum", "(D) A university"], "answer": "C"}, {"text": "Where is the exhibit located?", "options": ["(A) On the first floor", "(B) In the gift shop", "(C) On the third floor", "(D) In the basement"], "answer": "C"}, {"text": "What does the man ask about?", "options": ["(A) The closing time", "(B) The artist''s name", "(C) The location of the stairs", "(D) The cost of entry"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv21.mp3', true, NULL),
  (19, '[{"speaker": "M", "text": "Hi, I''m calling to see if the shoes I ordered online have arrived at the store yet."}, {"speaker": "F", "text": "Let me check the delivery log. What is the order number?"}, {"speaker": "M", "text": "It''s 8-2-2-4. I chose the \"in-store pickup\" option to save on shipping costs."}]', '[{"text": "What is the man inquiring about?", "options": ["(A) A refund policy", "(B) A delivery status", "(C) A store location", "(D) A price match"], "answer": "B"}, {"text": "How did the man purchase the item?", "options": ["(A) On the website", "(B) At the mall", "(C) Over the phone", "(D) At a factory outlet"], "answer": "A"}, {"text": "Why did the man choose in-store pickup?", "options": ["(A) It is faster", "(B) He lives nearby", "(C) To avoid a fee", "(D) To try them on first"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv31.mp3', true, NULL),
  (20, '[{"speaker": "F", "text": "My computer screen keeps flickering. Do you think it''s a loose cable?"}, {"speaker": "M", "text": "Let me check. Actually, it looks like the graphics card is failing. You''ll need a replacement."}, {"speaker": "F", "text": "That sounds expensive. Is it covered under the office warranty?"}]', '[{"text": "What is the problem?", "options": ["(A) A broken keyboard", "(B) A monitor issue", "(C) A power outage", "(D) A software virus"], "answer": "B"}, {"text": "What does the man suggest?", "options": ["(A) Buying a new cable", "(B) Restarting the computer", "(C) Replacing a part", "(D) Moving the desk"], "answer": "C"}, {"text": "What does the woman ask about?", "options": ["(A) The cost of a new computer", "(B) The technician''s schedule", "(C) A refund policy", "(D) Warranty coverage"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv04.mp3', true, NULL),
  (21, '[{"speaker": "M", "text": "Have you seen the draft for the new marketing brochure?"}, {"speaker": "F", "text": "Yes, but I think the font is a bit too small. It might be hard for some people to read."}, {"speaker": "M", "text": "You''re right. I''ll ask the graphic designer to increase the text size before we send it to the printer."}]', '[{"text": "What document are they discussing?", "options": ["(A) A legal contract", "(B) A promotional flyer", "(C) A financial report", "(D) A training manual"], "answer": "B"}, {"text": "What is the woman''s concern?", "options": ["(A) The color scheme", "(B) The total cost", "(C) The readability", "(D) The deadline"], "answer": "C"}, {"text": "What will the man do next?", "options": ["(A) Print the copies himself", "(B) Hire a new designer", "(C) Modify the layout", "(D) Write a new slogan"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv23.mp3', true, NULL),
  (22, '[{"speaker": "M", "text": "I''m calling to see if the repairs on my car will be finished today as promised."}, {"speaker": "F", "text": "I''m afraid not. We''re still waiting for the new brake pads to arrive from the warehouse."}, {"speaker": "M", "text": "That''s disappointing. I really need my car to get to the airport tomorrow morning."}]', '[{"text": "Why is the man calling?", "options": ["(A) To buy a new car", "(B) To rent a vehicle", "(C) To check on a repair", "(D) To report an accident"], "answer": "C"}, {"text": "What part is the shop waiting for?", "options": ["(A) A new engine", "(B) A tire", "(C) A window", "(D) Brake components"], "answer": "D"}, {"text": "Where does the man need to go tomorrow?", "options": ["(A) To his office", "(B) To the mall", "(C) To a wedding", "(D) To the airport"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv29.mp3', true, NULL),
  (23, '[{"speaker": "M", "text": "I''ve finished the draft for the annual report, but I need the sales figures for December."}, {"speaker": "F", "text": "I''m still waiting for the final numbers from the accounting department. They promised to have them by tomorrow."}, {"speaker": "M", "text": "That''s fine. I''ll work on the executive summary in the meantime."}]', '[{"text": "What has the man recently completed?", "options": ["(A) A sales pitch", "(B) A budget plan", "(C) A document draft", "(D) A hiring report"], "answer": "C"}, {"text": "Why is the report incomplete?", "options": ["(A) A computer error", "(B) Missing data", "(C) A sick employee", "(D) A late shipment"], "answer": "B"}, {"text": "What will the man do next?", "options": ["(A) Call accounting", "(B) Go home early", "(C) Write a summary", "(D) Print the report"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv42.mp3', true, NULL),
  (24, '[{"speaker": "F", "text": "Hello, I''d like to book a round-trip flight to Paris for the second week of June."}, {"speaker": "M", "text": "Certainly. Would you prefer a morning or an evening departure?"}, {"speaker": "F", "text": "Morning is better. I want to arrive early so I can get to my hotel before dinner."}]', '[{"text": "What is the woman doing?", "options": ["(A) Checking out of a hotel", "(B) Reserving a flight", "(C) Renting a car", "(D) Planning a dinner"], "answer": "B"}, {"text": "When does the woman want to travel?", "options": ["(A) In May", "(B) In June", "(C) In July", "(D) In August"], "answer": "B"}, {"text": "What is the woman''s preference?", "options": ["(A) A window seat", "(B) A direct flight", "(C) A morning flight", "(D) A cheap ticket"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv09.mp3', true, NULL),
  (25, '[{"speaker": "F", "text": "I''m looking for a new office chair. The one I have now doesn''t provide enough back support."}, {"speaker": "M", "text": "This ergonomic model is very popular. You can adjust the height and the armrests."}, {"speaker": "F", "text": "It''s comfortable, but it''s a bit over my budget. Do you have anything similar on sale?"}]', '[{"text": "What is the woman''s problem?", "options": ["(A) Her desk is too small", "(B) Her chair is uncomfortable", "(C) Her office is too dark", "(D) Her computer is broken"], "answer": "B"}, {"text": "What feature of the chair is mentioned?", "options": ["(A) It is made of leather", "(B) It has a built-in heater", "(C) It is adjustable", "(D) It comes in many colors"], "answer": "C"}, {"text": "What is the woman''s concern about the ergonomic chair?", "options": ["(A) The size", "(B) The weight", "(C) The color", "(D) The price"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv26.mp3', true, NULL),
  (26, '[{"speaker": "F", "text": "I''d like to sign up for a membership at this gym. Do you have a corporate discount for employees of \"Westside Electronics\"?"}, {"speaker": "M", "text": "We do! You''ll get 20% off the monthly fee and we''ll waive the registration cost."}, {"speaker": "F", "text": "That sounds great. Does that include access to the swimming pool?"}]', '[{"text": "What is the woman doing?", "options": ["(A) Buying electronics", "(B) Applying for a job", "(C) Joining a fitness club", "(D) Canceling a subscription"], "answer": "C"}, {"text": "What benefit is mentioned?", "options": ["(A) Free personal training", "(B) A free towel service", "(C) A price reduction", "(D) A 24-hour access pass"], "answer": "C"}, {"text": "What does the woman ask about?", "options": ["(A) The locker rooms", "(B) The yoga classes", "(C) The guest policy", "(D) The pool facilities"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv24.mp3', true, NULL),
  (27, '[{"speaker": "M", "text": "The shipment of office chairs was supposed to arrive this morning, but it''s still not here."}, {"speaker": "F", "text": "I just spoke to the trucking company. There was an accident on the highway, so they are delayed."}, {"speaker": "M", "text": "I hope the chairs aren''t damaged. We need them for the new employees starting on Monday."}]', '[{"text": "What are the speakers waiting for?", "options": ["(A) New employees", "(B) Furniture", "(C) A repairman", "(D) A cleaning crew"], "answer": "B"}, {"text": "Why is the delivery late?", "options": ["(A) A traffic incident", "(B) Bad weather", "(C) A missing order", "(D) Vehicle breakdown"], "answer": "A"}, {"text": "When are the new staff members starting?", "options": ["(A) Today", "(B) Tomorrow", "(C) Next Monday", "(D) Next month"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv37.mp3', true, NULL),
  (28, '[{"speaker": "M", "text": "Did you hear that the library is closing for three weeks for renovations?"}, {"speaker": "F", "text": "Yes, I saw the sign. They are replacing all the carpets and repainting the interior."}, {"speaker": "M", "text": "I hope I can still return my books while they are closed."}]', '[{"text": "What is the topic of conversation?", "options": ["(A) A book sale", "(B) A painting class", "(C) A temporary closure", "(D) A library membership"], "answer": "C"}, {"text": "What work is being done?", "options": ["(A) Building a new wing", "(B) Installing new computers", "(C) Cleaning the windows", "(D) Updating the decor"], "answer": "D"}, {"text": "What is the man''s concern?", "options": ["(A) Finding a new library", "(B) Missing a deadline", "(C) Paying for renovations", "(D) Returning borrowed items"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv15.mp3', true, NULL),
  (29, '[{"speaker": "M", "text": "The elevator is out of order again. I had to walk up six flights of stairs!"}, {"speaker": "F", "text": "They are waiting for a part to be shipped from Germany. It should be fixed by Friday."}, {"speaker": "M", "text": "Well, I guess I''ll get some exercise until then."}]', '[{"text": "What is the man complaining about?", "options": ["(A) The heat", "(B) The stairs", "(C) Broken machinery", "(D) A late delivery"], "answer": "C"}, {"text": "Where is the replacement part coming from?", "options": ["(A) Japan", "(B) The local shop", "(C) Germany", "(D) The basement"], "answer": "C"}, {"text": "When will the repair likely be finished?", "options": ["(A) Today", "(B) Tomorrow", "(C) Monday", "(D) Friday"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv06.mp3', true, NULL),
  (30, '[{"speaker": "F", "text": "I''m thinking about taking the express bus to work starting next week. Parking prices downtown have doubled."}, {"speaker": "M", "text": "It''s a good move. The bus lane makes the commute much faster during rush hour anyway."}, {"speaker": "F", "text": "True, and I can use the company''s transit subsidy to pay for the monthly pass."}]', '[{"text": "Why does the woman want to stop driving?", "options": ["(A) Her car is being repaired", "(B) She wants to help the environment", "(C) Traffic is too heavy", "(D) Parking is too expensive"], "answer": "D"}, {"text": "What benefit of the bus does the man mention?", "options": ["(A) It is very clean", "(B) It has free Wi-Fi", "(C) It saves time", "(D) It is less crowded"], "answer": "C"}, {"text": "How will the woman pay for her pass?", "options": ["(A) With her own savings", "(B) Using a credit card", "(C) With a gift voucher", "(D) Through a workplace program"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv14.mp3', true, NULL),
  (31, '[{"speaker": "F", "text": "Is the museum open on Mondays? I have a friend visiting from out of town."}, {"speaker": "M", "text": "No, we''re closed on Mondays for maintenance, but we stay open late on Fridays."}, {"speaker": "F", "text": "That''s good to know. We''ll go on Friday evening then."}]', '[{"text": "When is the museum closed?", "options": ["(A) Fridays", "(B) Saturdays", "(C) Mondays", "(D) Sundays"], "answer": "C"}, {"text": "Why is the museum closed on that day?", "options": ["(A) Lack of staff", "(B) Private events", "(C) Maintenance work", "(D) Holiday break"], "answer": "C"}, {"text": "What is special about Fridays?", "options": ["(A) Free entry", "(B) Guided tours", "(C) Extra hours", "(D) Live music"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv51.mp3', true, NULL),
  (32, '[{"speaker": "F", "text": "Have you had a chance to look at the draft of the merger announcement?"}, {"speaker": "M", "text": "I have. I think we need to emphasize the benefits for the shareholders more clearly."}, {"speaker": "F", "text": "I agree. I''ll rewrite that section and send you a second draft by the end of the day."}]', '[{"text": "What document are they discussing?", "options": ["(A) A press release", "(B) A budget report", "(C) A job offer", "(D) A sales contract"], "answer": "A"}, {"text": "What does the man suggest changing?", "options": ["(A) The fonts and colors", "(B) The focus of the content", "(C) The deadline", "(D) The distribution list"], "answer": "B"}, {"text": "What will the woman do next?", "options": ["(A) Print the document", "(B) Call the shareholders", "(C) Revise the text", "(D) Send an email"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv38.mp3', true, NULL),
  (33, '[{"speaker": "F", "text": "I''m sorry, Mr. Jackson, but the 10:30 flight to Toronto has been canceled due to a technical issue."}, {"speaker": "M", "text": "That''s a problem. I have a client meeting at 2:00 PM. Are there any other flights available before noon?"}, {"speaker": "F", "text": "There is one at 11:15, but it''s currently full. I can put you on the waiting list."}]', '[{"text": "Why was the flight canceled?", "options": ["(A) Severe weather", "(B) Lack of passengers", "(C) Mechanical failure", "(D) A pilot strike"], "answer": "C"}, {"text": "What is the man''s destination?", "options": ["(A) New York", "(B) London", "(C) Montreal", "(D) Toronto"], "answer": "D"}, {"text": "What does the woman offer to do?", "options": ["(A) Give a full refund", "(B) Provide a hotel voucher", "(C) Add the man to a list", "(D) Upgrade his seat for free"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv22.mp3', true, NULL),
  (34, '[{"speaker": "F", "text": "We need to schedule a training session for the new database software."}, {"speaker": "M", "text": "The developer said they could come in next Tuesday at 10:00 AM."}, {"speaker": "F", "text": "Tuesday won''t work. Most of the sales team will be at a regional conference that day."}]', '[{"text": "What is the purpose of the meeting?", "options": ["(A) To hire a developer", "(B) To fix a computer", "(C) To learn a new system", "(D) To update a website"], "answer": "C"}, {"text": "When did the developer suggest meeting?", "options": ["(A) Monday", "(B) Tuesday", "(C) Wednesday", "(D) Thursday"], "answer": "B"}, {"text": "Why is the suggested time a problem?", "options": ["(A) The office will be closed", "(B) The manager is on vacation", "(C) The room is booked", "(D) Staff members will be away"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv18.mp3', true, NULL),
  (35, '[{"speaker": "M", "text": "I''m worried about the presentation tomorrow. My laptop doesn''t have an HDMI port for the projector."}, {"speaker": "F", "text": "You can borrow the adapter from the IT department. They keep several in the supply room."}, {"speaker": "M", "text": "That''s a relief. I''ll go down there and ask for one before I leave for the day."}]', '[{"text": "What is the man preparing for?", "options": ["(A) A business trip", "(B) A presentation", "(C) A job interview", "(D) A staff meeting"], "answer": "B"}, {"text": "What is the problem with the man''s laptop?", "options": ["(A) The battery is low", "(B) It lacks a connection port", "(C) The screen is dark", "(D) The software is old"], "answer": "B"}, {"text": "What does the woman suggest?", "options": ["(A) Buying a new laptop", "(B) Rescheduling the talk", "(C) Borrowing an accessory", "(D) Printing the slides"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv35.mp3', true, NULL),
  (36, '[{"speaker": "M", "text": "I need to book a flight to Chicago for the trade show next month."}, {"speaker": "F", "text": "You should book it today. Prices usually go up after the 15th of the month."}, {"speaker": "M", "text": "Thanks for the tip. I''ll go online and do it during my break."}]', '[{"text": "Where is the man going?", "options": ["(A) New York", "(B) Chicago", "(C) Los Angeles", "(D) Miami"], "answer": "B"}, {"text": "Why is the man traveling?", "options": ["(A) For a wedding", "(B) For a vacation", "(C) For an event", "(D) For a family visit"], "answer": "C"}, {"text": "What does the woman suggest about the timing?", "options": ["(A) Wait for a sale", "(B) Book in the morning", "(C) Purchase tickets now", "(D) Change the destination"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv52.mp3', true, NULL),
  (37, '[{"speaker": "M", "text": "Hi, Sarah. Have you finished the quarterly budget review yet?"}, {"speaker": "F", "text": "Not quite. I''m still waiting for the travel expenses from the marketing department."}, {"speaker": "M", "text": "I''ll call the marketing manager, Mr. Evans, and ask him to send them over immediately."}]', '[{"text": "What is the woman currently working on?", "options": ["(A) A marketing campaign", "(B) A budget review", "(C) A travel itinerary", "(D) A hiring plan"], "answer": "B"}, {"text": "Why is the task delayed?", "options": ["(A) Some information is missing", "(B) The computer is broken", "(C) Mr. Evans is on vacation", "(D) The office is closed"], "answer": "A"}, {"text": "What will the man do next?", "options": ["(A) Go to the marketing office", "(B) Email the department", "(C) Make a phone call", "(D) Sign a contract"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv01.mp3', true, NULL),
  (38, '[{"speaker": "F", "text": "I''d like to register for the yoga class that starts next Monday."}, {"speaker": "M", "text": "Certainly. That class meets twice a week, on Mondays and Wednesdays, at 6:30 PM."}, {"speaker": "F", "text": "That schedule works perfectly with my office hours. How much is the registration fee?"}]', '[{"text": "What is the woman interested in?", "options": ["(A) A gym membership", "(B) An exercise class", "(C) A dance lesson", "(D) A meditation app"], "answer": "B"}, {"text": "On which days does the class meet?", "options": ["(A) Mondays and Wednesdays", "(B) Tuesdays and Thursdays", "(C) Weekends only", "(D) Every Friday"], "answer": "A"}, {"text": "What does the woman ask about?", "options": ["(A) The location", "(B) The instructor", "(C) The cost", "(D) The clothing"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv36.mp3', true, NULL),
  (39, '[{"speaker": "M", "text": "This smartphone has a great camera, but the battery life is quite short."}, {"speaker": "F", "text": "That model is on sale right now, but for $50 more, you can get the \"Pro\" version with a larger battery."}, {"speaker": "M", "text": "I think it''s worth the extra money since I travel so much and can''t always find a charger."}]', '[{"text": "What are the speakers discussing?", "options": ["(A) A camera repair", "(B) A travel itinerary", "(C) An electronic device", "(D) A battery charger"], "answer": "C"}, {"text": "What is the drawback of the first model?", "options": ["(A) It is too heavy", "(B) It is very expensive", "(C) The camera is poor", "(D) It lacks power longevity"], "answer": "D"}, {"text": "Why does the man decide on the more expensive option?", "options": ["(A) It has more storage", "(B) It is more stylish", "(C) It is better for his lifestyle", "(D) It comes with a free case"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv17.mp3', true, NULL),
  (40, '[{"speaker": "F", "text": "Excuse me, is the fitness center open 24 hours a day for hotel guests?"}, {"speaker": "M", "text": "No, it closes at 10:00 PM and reopens at 5:00 AM."}, {"speaker": "F", "text": "I see. I was hoping to get a workout in before my flight leaves at 6:00 AM, but I guess I''ll have to skip it."}]', '[{"text": "Where is this conversation taking place?", "options": ["(A) A gym", "(B) A hotel", "(C) An airport", "(D) A doctor''s office"], "answer": "B"}, {"text": "When does the fitness center open?", "options": ["(A) At 5:00 AM", "(B) At 6:00 AM", "(C) At 10:00 PM", "(D) At midnight"], "answer": "A"}, {"text": "Why is the woman disappointed?", "options": ["(A) The equipment is broken", "(B) The pool is closed", "(C) The hours are inconvenient", "(D) She lost her room key"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv34.mp3', true, NULL),
  (41, '[{"speaker": "F", "text": "I''m having trouble using the new photocopier. It keeps jamming every time I try to print on both sides."}, {"speaker": "M", "text": "You have to make sure the paper tray is adjusted correctly for that setting."}, {"speaker": "F", "text": "Oh, I see. Could you show me how to do that? I have to make 50 copies of this report."}]', '[{"text": "What machine is the woman using?", "options": ["(A) A computer", "(B) A scanner", "(C) A copier", "(D) A fax machine"], "answer": "C"}, {"text": "What is the problem?", "options": ["(A) The ink is empty", "(B) The machine is too slow", "(C) A paper jam", "(D) The power is off"], "answer": "C"}, {"text": "What does the woman ask the man to do?", "options": ["(A) Call a technician", "(B) Buy more paper", "(C) Demonstrate a fix", "(D) Print the report for her"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv30.mp3', true, NULL),
  (42, '[{"speaker": "M", "text": "Does this laptop come with a carrying case, or do I have to purchase one separately?"}, {"speaker": "F", "text": "It''s included in the price this week as part of our \"Back to School\" promotion."}, {"speaker": "M", "text": "That''s a great deal. I''ll take the silver model, please."}]', '[{"text": "What is the man buying?", "options": ["(A) A briefcase", "(B) A tablet", "(C) A computer", "(D) A school bag"], "answer": "C"}, {"text": "What is mentioned about the carrying case?", "options": ["(A) It is on sale", "(B) It is out of stock", "(C) It is a separate charge", "(D) It is free with purchase"], "answer": "D"}, {"text": "Which model did the man choose?", "options": ["(A) The black one", "(B) The gold one", "(C) The blue one", "(D) The silver one"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv46.mp3', true, NULL),
  (43, '[{"speaker": "M", "text": "I''m calling to confirm the delivery time for the new office furniture."}, {"speaker": "F", "text": "It''s scheduled for Thursday morning between 9:00 and 11:00."}, {"speaker": "M", "text": "Can we move it to the afternoon? We have a staff meeting in the lobby all morning."}]', '[{"text": "Why is the man calling?", "options": ["(A) To order furniture", "(B) To cancel a delivery", "(C) To verify a schedule", "(D) To complain about a price"], "answer": "C"}, {"text": "When was the original delivery time?", "options": ["(A) Wednesday morning", "(B) Thursday morning", "(C) Thursday afternoon", "(D) Friday morning"], "answer": "B"}, {"text": "What is happening in the lobby on Thursday morning?", "options": ["(A) A renovation", "(B) A cleaning service", "(C) A client visit", "(D) A staff meeting"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv48.mp3', true, NULL),
  (44, '[{"speaker": "M", "text": "I need to ship this package to Tokyo by Friday. Which service do you recommend?"}, {"speaker": "F", "text": "Our express international shipping is the fastest, but it''s quite expensive. It should arrive in two days."}, {"speaker": "M", "text": "I''ll take that option. It''s a very important contract that needs to be signed by Monday."}]', '[{"text": "Where is the package being sent?", "options": ["(A) Seoul", "(B) Shanghai", "(C) Tokyo", "(D) Singapore"], "answer": "C"}, {"text": "Why does the man choose the express service?", "options": ["(A) It is the cheapest option", "(B) It includes insurance", "(C) It is time-sensitive", "(D) It is a large box"], "answer": "C"}, {"text": "What is inside the package?", "options": ["(A) A birthday gift", "(B) A new computer", "(C) Legal documents", "(D) Office supplies"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv25.mp3', true, NULL),
  (45, '[{"speaker": "M", "text": "Are you ready for your presentation this afternoon?"}, {"speaker": "F", "text": "I''m a bit nervous. I haven''t checked if the projector in the conference room works."}, {"speaker": "M", "text": "Don''t worry, I used it this morning for the staff meeting and it worked perfectly."}]', '[{"text": "When is the woman''s presentation?", "options": ["(A) This morning", "(B) This afternoon", "(C) Tomorrow", "(D) Next week"], "answer": "B"}, {"text": "Why is the woman concerned?", "options": ["(A) She forgot her notes", "(B) The audience is large", "(C) She hasn''t practiced", "(D) Equipment functionality"], "answer": "D"}, {"text": "What did the man do this morning?", "options": ["(A) Fixed a projector", "(B) Prepared a speech", "(C) Attended a meeting", "(D) Called a technician"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv05.mp3', true, NULL),
  (46, '[{"speaker": "M", "text": "I''m thinking about signing up for a Spanish course this semester."}, {"speaker": "F", "text": "That''s a great idea! I took a class last year, and it''s been very helpful during my business trips."}, {"speaker": "M", "text": "I''m just not sure if I should take the evening class or the Saturday morning session."}]', '[{"text": "What is the man considering?", "options": ["(A) Moving to Spain", "(B) Learning a language", "(C) Buying a book", "(D) Taking a vacation"], "answer": "B"}, {"text": "Why was the class helpful for the woman?", "options": ["(A) For her hobby", "(B) For her travel", "(C) For her grades", "(D) For her family"], "answer": "B"}, {"text": "What is the man undecided about?", "options": ["(A) The cost", "(B) The teacher", "(C) The time", "(D) The level"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv39.mp3', true, NULL),
  (47, '[{"speaker": "F", "text": "Hello, I''d like to make a reservation for a party of six for tomorrow evening at 7:00."}, {"speaker": "M", "text": "I''m sorry, we are fully booked at 7:00. We have a table available at 8:30, though."}, {"speaker": "F", "text": "That''s a bit late for us. How about Friday night instead?"}]', '[{"text": "What is the woman trying to do?", "options": ["(A) Order a pizza", "(B) Rent a room", "(C) Book a table", "(D) Hire a waiter"], "answer": "C"}, {"text": "How many people are in the group?", "options": ["(A) Two", "(B) Four", "(C) Six", "(D) Eight"], "answer": "C"}, {"text": "What does the woman suggest at the end?", "options": ["(A) Coming at 8:30", "(B) Ordering take-out", "(C) Finding a new restaurant", "(D) Changing the day"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv28.mp3', true, NULL),
  (48, '[{"speaker": "M", "text": "The air conditioning in the breakroom isn''t working. It''s nearly 30 degrees in there!"}, {"speaker": "F", "text": "I already called maintenance. They said they''ll send someone up after they finish fixing the elevator."}, {"speaker": "M", "text": "I hope they hurry. I can''t eat my lunch in that heat."}]', '[{"text": "What is the problem in the breakroom?", "options": ["(A) The lights are off", "(B) The fridge is broken", "(C) The temperature is too high", "(D) The floor is wet"], "answer": "C"}, {"text": "What is the maintenance team currently doing?", "options": ["(A) Fixing a leak", "(B) Repairing an elevator", "(C) Painting a wall", "(D) Installing a fan"], "answer": "B"}, {"text": "How does the man feel?", "options": ["(A) Excitement", "(B) Boredom", "(C) Impatience", "(D) Surprise"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv44.mp3', true, NULL),
  (49, '[{"speaker": "M", "text": "I just checked the supply closet, and we are completely out of printer toner and legal-sized paper."}, {"speaker": "F", "text": "That''s strange. I placed an order with the vendor last Friday. They usually deliver within 48 hours."}, {"speaker": "M", "text": "I''ll give them a call and see if there was a delay with the shipment."}]', '[{"text": "What is the problem?", "options": ["(A) The printer is broken", "(B) The supply closet is locked", "(C) Office materials are missing", "(D) The vendor changed their prices"], "answer": "C"}, {"text": "When did the woman place the order?", "options": ["(A) This morning", "(B) Yesterday", "(C) Last Wednesday", "(D) Last Friday"], "answer": "D"}, {"text": "What will the man do next?", "options": ["(A) Buy paper at a local store", "(B) Organize the closet", "(C) Contact a supplier", "(D) Print a different document"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv11.mp3', true, NULL),
  (50, '[{"speaker": "F", "text": "I''m sorry, but the main auditorium is being used for a private event this evening."}, {"speaker": "M", "text": "Oh, I thought the lecture on urban planning was held there. Is it canceled?"}, {"speaker": "F", "text": "No, it''s been moved to the small conference room on the second floor."}]', '[{"text": "Why is the auditorium unavailable?", "options": ["(A) It is under repair", "(B) It is being cleaned", "(C) A private function is occurring", "(D) The power is out"], "answer": "C"}, {"text": "What is the topic of the lecture?", "options": ["(A) History", "(B) Gardening", "(C) City development", "(D) Business law"], "answer": "C"}, {"text": "Where should the man go now?", "options": ["(A) The lobby", "(B) The library", "(C) The basement", "(D) The second floor"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv41.mp3', true, NULL),
  (51, '[{"speaker": "M", "text": "Have you seen the new employee handbook? It was updated last night."}, {"speaker": "F", "text": "I haven''t. Did they change the policy on remote work?"}, {"speaker": "M", "text": "Yes, we are now allowed to work from home two days a week instead of just one."}]', '[{"text": "What was recently updated?", "options": ["(A) The company website", "(B) The office layout", "(C) A reference document", "(D) The software system"], "answer": "C"}, {"text": "What specific policy is discussed?", "options": ["(A) The dress code", "(B) Vacation time", "(C) Retirement plans", "(D) Remote work"], "answer": "D"}, {"text": "What is the new rule?", "options": ["(A) No working from home", "(B) One day of remote work", "(C) Two days of remote work", "(D) Full-time remote work"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv10.mp3', true, NULL),
  (52, '[{"speaker": "M", "text": "We need to hire a photographer for the company gala next month."}, {"speaker": "F", "text": "I know a freelancer who specializes in corporate events. I can send you her portfolio."}, {"speaker": "M", "text": "That would be great. We need someone who can take both candid shots and group portraits."}]', '[{"text": "What is the topic of the conversation?", "options": ["(A) Organizing a party", "(B) Hiring a professional", "(C) Taking a vacation", "(D) Buying a camera"], "answer": "B"}, {"text": "What will the woman provide?", "options": ["(A) A price list", "(B) A camera", "(C) Samples of work", "(D) A guest list"], "answer": "C"}, {"text": "When is the gala taking place?", "options": ["(A) This week", "(B) In two weeks", "(C) Next month", "(D) Next year"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part3/audio/conv08.mp3', true, NULL);
INSERT INTO toeic_listening_part4
  (position, title, text, questions, audio_url, is_exam, dataset_id)
VALUES
  (1, 'Voicemail Message', 'Hi, this is Linda from Sunnyvale Travel. I''m calling to let you know that your hotel reservation in Madrid has been confirmed. However, the hotel notified us that their rooftop pool will be closed for maintenance during your stay. As an apology, they are offering you a voucher for a free dinner at their award-winning restaurant. I''ll email the voucher to you shortly.', '[{"text": "What is the purpose of the call?", "options": ["(A) To book a flight", "(B) To confirm a hotel stay", "(C) To cancel a tour", "(D) To request a payment"], "answer": "B"}, {"text": "What is the problem mentioned?", "options": ["(A) The room is not ready", "(B) The flight was delayed", "(C) A facility is unavailable", "(D) The price has increased"], "answer": "C"}, {"text": "What will the speaker send to the listener?", "options": ["(A) A map of Madrid", "(B) A dinner voucher", "(C) A new itinerary", "(D) A refund check"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk11.mp3', true, NULL),
  (2, 'Introduction', 'It is my great pleasure to introduce our keynote speaker, Dr. Elena Rossi. Dr. Rossi has spent the last decade researching renewable energy at the University of Rome. Today, she will discuss her latest project involving solar-powered water filtration systems. Please join me in giving her a warm welcome.', '[{"text": "Who is the speaker introducing?", "options": ["(A) A university student", "(B) A research assistant", "(C) A keynote speaker", "(D) A project manager"], "answer": "C"}, {"text": "What is Dr. Rossi''s area of expertise?", "options": ["(A) Water management", "(B) Ancient history", "(C) Renewable energy", "(D) Italian architecture"], "answer": "C"}, {"text": "What is the specific topic of the speech?", "options": ["(A) University of Rome''s history", "(B) Solar water filtration", "(C) Future of Italian politics", "(D) How to get a research grant"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk08.mp3', true, NULL),
  (3, 'Business Briefing', 'Good morning, everyone. Before we start our shift, I have an update regarding our new software system. We were supposed to transition to ''CloudSync'' today, but the IT team found a bug in the security settings. Therefore, we will continue using our current system until Monday. Please attend the training session in the conference room at 2:00 PM today as scheduled.', '[{"text": "What is the purpose of the talk?", "options": ["(A) To introduce a new employee", "(B) To announce a delay", "(C) To complain about a security breach", "(D) To cancel a training session"], "answer": "B"}, {"text": "What happened to the ''CloudSync'' launch?", "options": ["(A) It was successful", "(B) It was moved to 2:00 PM", "(C) It was rescheduled for next week", "(D) It was permanently canceled"], "answer": "C"}, {"text": "What should the listeners do at 2:00 PM?", "options": ["(A) Start using the new software", "(B) Go to the conference room", "(C) Call the IT department", "(D) Leave work early"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk03.mp3', true, NULL),
  (4, 'Public Announcement', 'Attention passengers at Central Station. Due to mechanical issues on the tracks near the bridge, all Express trains have been suspended until further notice. Passengers traveling northbound should take the next Local train instead. Please note that the Local train will depart from its usual location as shown on the schedule. We apologize for the delay.', '[{"text": "Why are some trains suspended?", "options": ["(A) Bad weather", "(B) Staff shortages", "(C) Track maintenance", "(D) Mechanical problems"], "answer": "D"}, {"text": "Look at the graphic. Which platform should passengers go to for the next available train?", "options": ["(A) Platform 1", "(B) Platform 2", "(C) Platform 3", "(D) Platform 4"], "answer": "D"}, {"text": "What does the speaker suggest passengers do?", "options": ["(A) Wait for the Express", "(B) Take a Local train", "(C) Ask for a refund", "(D) Travel southbound"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk22.mp3', true, NULL),
  (5, 'Business Briefing', 'Good morning, team. I have a quick update regarding our client, Nexus Corp. They''ve requested a change in the color scheme for the new website design. Instead of the blue and grey we originally proposed, they want a more vibrant green and white theme to match their new branding. Please pause work on the current layout until the design team sends over the updated style guide this afternoon.', '[{"text": "What is the talk mainly about?", "options": ["(A) A new project deadline", "(B) A change in design requirements", "(C) A budget increase", "(D) A client meeting schedule"], "answer": "B"}, {"text": "What color combination does the client now want?", "options": ["(A) Blue and grey", "(B) Red and black", "(C) Green and white", "(D) Yellow and orange"], "answer": "C"}, {"text": "What are the listeners told to do?", "options": ["(A) Call the client", "(B) Stop working on the layout", "(C) Finish the blue design", "(D) Go home early"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk21.mp3', true, NULL),
  (6, 'Business News', 'In business news today, the tech giant ''Aperion'' has announced it will be opening a new headquarters in Austin, Texas. This move is expected to create over 2,000 jobs in the local area over the next two years. The company cited the city''s growing talent pool and favorable tax environment as the primary reasons for the relocation. Construction is set to begin this July.', '[{"text": "What did the company ''Aperion'' announce?", "options": ["(A) A merger", "(B) A new office location", "(C) A product recall", "(D) A bankruptcy filing"], "answer": "B"}, {"text": "How many jobs will be created?", "options": ["(A) 500", "(B) 1,000", "(C) 2,000", "(D) 5,000"], "answer": "C"}, {"text": "When will construction start?", "options": ["(A) This July", "(B) This December", "(C) Next January", "(D) Next July"], "answer": "A"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk19.mp3', true, NULL),
  (7, 'Public Announcement', 'Welcome to the Metropolitan Museum. We are currently hosting a special temporary exhibit of marble statues from the 20th century. This collection is located in the hall directly adjacent to the Renaissance Art gallery. Please note that sketches are allowed, but the use of charcoal is prohibited. After your visit, please exit through the designated area to browse our selection of art books and souvenirs.', '[{"text": "What is the special exhibit featuring?", "options": ["(A) Oil paintings", "(B) Ancient coins", "(C) Modern sculptures", "(D) Photography"], "answer": "C"}, {"text": "Look at the graphic. In which room is the special exhibit located?", "options": ["(A) Room A", "(B) Room B", "(C) Room C", "(D) Room D"], "answer": "C"}, {"text": "What are visitors allowed to do?", "options": ["(A) Use charcoal", "(B) Take photographs", "(C) Touch the statues", "(D) Draw sketches"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk35.mp3', true, NULL),
  (8, 'Voicemail Message', 'Hi, this is Jessica from the catering company. I''m calling about your order for the retirement party this Friday. You requested 50 vegetarian wraps, but our supplier just informed us they are out of the spinach tortillas you wanted. We can substitute them with whole-wheat tortillas instead. Please let me know if this is acceptable by 4:00 PM today.', '[{"text": "What is the reason for the call?", "options": ["(A) To confirm a delivery time", "(B) To suggest an ingredient change", "(C) To request a payment", "(D) To cancel an event"], "answer": "B"}, {"text": "What event is being catered?", "options": ["(A) A wedding", "(B) A birthday party", "(C) A retirement party", "(D) A business lunch"], "answer": "C"}, {"text": "When does the listener need to respond?", "options": ["(A) This Friday", "(B) By 4:00 PM today", "(C) In one hour", "(D) Tomorrow morning"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk26.mp3', true, NULL),
  (9, 'Tour Guide', 'As we walk through the botanical garden''s Tropical House, please be aware of the high humidity levels, which are necessary for these exotic ferns. To your left is the rare Orchid collection. These flowers only bloom once every three years. Please stay on the paved path and refrain from touching the plants. Our next stop will be the Butterfly Pavilion.', '[{"text": "Where is the speaker?", "options": ["(A) A zoo", "(B) A botanical garden", "(C) A farm", "(D) A park"], "answer": "B"}, {"text": "What is special about the Orchids mentioned?", "options": ["(A) They are very large", "(B) They are blue", "(C) They bloom infrequently", "(D) They are used for medicine"], "answer": "C"}, {"text": "What will the group visit next?", "options": ["(A) The gift shop", "(B) The exit", "(C) The Butterfly Pavilion", "(D) The rose garden"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk28.mp3', true, NULL),
  (10, 'Voicemail Message', 'Hello, this is Marcus from the maintenance department. I''m calling regarding your request to fix the overhead lights in office 402. I was planning to come by this afternoon, but a pipe burst in the basement, and I need to prioritize that. I''ll be there tomorrow morning at 9:00 AM instead. Sorry for the inconvenience.', '[{"text": "Where does the speaker work?", "options": ["(A) Human Resources", "(B) Maintenance", "(C) Accounting", "(D) Security"], "answer": "B"}, {"text": "What was the original problem?", "options": ["(A) A broken window", "(B) A leaking pipe", "(C) A faulty light fixture", "(D) A noisy air conditioner"], "answer": "C"}, {"text": "When will the speaker arrive?", "options": ["(A) This afternoon", "(B) Tomorrow morning", "(C) Next week", "(D) In two days"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk01.mp3', true, NULL),
  (11, 'Weather Report', 'It''s going to be a day of drastic changes, folks. We''re starting off quite chilly, but once the sun comes out, we''ll see a pleasant rise in temperature. In fact, the warmest part of the day will be nearly double the temperature we have right now. However, once the sun sets, the temperature will drop rapidly, and we may even see some frost on the ground late tonight.', '[{"text": "What is the main topic of the report?", "options": ["(A) Approaching rain", "(B) Wind speeds", "(C) Temperature fluctuations", "(D) Storm warnings"], "answer": "C"}, {"text": "Look at the graphic. What is the peak temperature expected today?", "options": ["(A) 12°C", "(B) 22°C", "(C) 10°C", "(D) 4°C"], "answer": "B"}, {"text": "What might happen tonight?", "options": ["(A) A thunderstorm", "(B) Heavy fog", "(C) Frost formation", "(D) High winds"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk29.mp3', true, NULL),
  (12, 'Product Advertisement', 'Are you looking for a better way to manage your team''s schedule? Try ''TaskMaster Pro.'' Our software allows you to assign tasks and track progress in real-time. For a limited time, we are offering our most popular option—which allows up to five users—at a 25% discount. It''s perfect for small households or small business teams. Download your free trial today!', '[{"text": "What does the software help users do?", "options": ["(A) Edit photos", "(B) Manage schedules", "(C) Design websites", "(D) Write code"], "answer": "B"}, {"text": "Look at the graphic. Which plan is the speaker offering a discount on?", "options": ["(A) Basic", "(B) Family", "(C) Premium", "(D) Business"], "answer": "B"}, {"text": "What is available for free?", "options": ["(A) A mobile phone", "(B) A training session", "(C) A software trial", "(D) A customer support call"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk40.mp3', true, NULL),
  (13, 'Excerpt from a Meeting', 'Thank you all for coming. Let''s look at where we stand on the new smartphone project. The research phase took longer than expected, but it gave us great insights. Currently, the engineering team is building the first physical model. We expect to move into the trial phase by early next month. If we stay on track, we will hit the mass manufacturing stage by the end of the year.', '[{"text": "What is the meeting about?", "options": ["(A) A marketing strategy", "(B) A product development update", "(C) A quarterly budget review", "(D) An employee training session"], "answer": "B"}, {"text": "Look at the graphic. Which stage of the project is the team currently working on?", "options": ["(A) Research", "(B) Prototype", "(C) Testing", "(D) Production"], "answer": "B"}, {"text": "When does the speaker hope to start mass manufacturing?", "options": ["(A) Next month", "(B) In three months", "(C) By the end of the year", "(D) Next summer"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk25.mp3', true, NULL),
  (14, 'Advertisement', 'Is your lawn looking tired and brown? Call GreenThumb Landscaping today! We offer a full range of services, from basic mowing to complex garden design. If you sign up for a one-year contract this month, we''ll include free monthly fertilization. Visit our website to see photos of our previous projects.', '[{"text": "What service does the company provide?", "options": ["(A) Interior design", "(B) Carpet cleaning", "(C) Yard maintenance", "(D) House painting"], "answer": "C"}, {"text": "How can customers get a free service?", "options": ["(A) By visiting the website", "(B) By referring a friend", "(C) By posting a photo", "(D) By signing a long-term agreement"], "answer": "D"}, {"text": "What is available on the company''s website?", "options": ["(A) A price calculator", "(B) Images of past work", "(C) A list of employees", "(D) An online chat feature"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk04.mp3', true, NULL),
  (15, 'Public Announcement', 'Attention all shoppers. We are happy to announce that for the next hour, we are having a flash sale on all smart televisions and kitchen mixers. Please head to the appropriate floor to take advantage of these 30% discounts. Also, don''t forget to visit our bakery for a free sample of our new sourdough bread.', '[{"text": "What is being offered at a discount?", "options": ["(A) Shoes", "(B) Groceries", "(C) Appliances", "(D) Furniture"], "answer": "C"}, {"text": "Look at the graphic. Which floor should customers go to for the flash sale?", "options": ["(A) Floor 1", "(B) Floor 2", "(C) Floor 3", "(D) Floor 4"], "answer": "C"}, {"text": "What can shoppers get for free?", "options": ["(A) A television", "(B) A sourdough sample", "(C) A store catalog", "(D) A discount coupon"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk02.mp3', true, NULL),
  (16, 'Telephone Message', 'Hello, this is Mr. Henderson from the accounting department. I''m calling to follow up on the invoice I sent you last Tuesday. We noticed that the total amount listed was incorrect because the shipping charges were not included. I have sent a revised invoice to your email address. Please ignore the first one and use the new document for your payment records.', '[{"text": "Where does the speaker work?", "options": ["(A) Shipping", "(B) Accounting", "(C) Sales", "(D) Human Resources"], "answer": "B"}, {"text": "What was wrong with the original invoice?", "options": ["(A) The date was wrong", "(B) It was missing a signature", "(C) It had an incorrect total", "(D) It was sent to the wrong person"], "answer": "C"}, {"text": "What should the listener do?", "options": ["(A) Pay the first invoice", "(B) Use the revised document", "(C) Call Mr. Henderson back", "(D) Send a shipping receipt"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk23.mp3', true, NULL),
  (17, 'Public Service Announcement', 'The City Water Department will be conducting maintenance on the main pipelines in the West End district this Sunday. Residents in the area may experience low water pressure or temporary service interruptions between 8:00 AM and 2:00 PM. We recommend storing enough water for your household needs on Saturday evening. We appreciate your patience during these necessary repairs.', '[{"text": "What is happening this Sunday?", "options": ["(A) A street fair", "(B) Utility maintenance", "(C) A marathon", "(D) A recycling drive"], "answer": "B"}, {"text": "What is a possible problem for residents?", "options": ["(A) Power outages", "(B) No internet access", "(C) Low water pressure", "(D) Closed roads"], "answer": "C"}, {"text": "What does the speaker suggest doing on Saturday?", "options": ["(A) Calling the department", "(B) Buying bottled water", "(C) Cleaning the house", "(D) Saving a water supply"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk27.mp3', true, NULL),
  (18, 'Voicemail Message', 'Hello, this is David from the IT department. I received your message about your computer not connecting to the office printer. I''ve checked the server and everything seems fine on our end, so it might be a hardware issue with your specific machine. I''ll be tied up in meetings all morning, so please call the main desk to see if another technician is available to assist you before noon.', '[{"text": "What is the listener''s problem?", "options": ["(A) A forgotten password", "(B) A printer connection issue", "(C) A broken monitor", "(D) A missing file"], "answer": "B"}, {"text": "Why is the speaker unable to help immediately?", "options": ["(A) He is on vacation", "(B) He is fixing a server", "(C) He is in meetings", "(D) He is out of the office"], "answer": "C"}, {"text": "Look at the graphic. Which extension should the listener dial to find another technician?", "options": ["(A) Ext. 10", "(B) Ext. 20", "(C) Ext. 30", "(D) Ext. 0"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk15.mp3', true, NULL),
  (19, 'Business Presentation', 'Take a look at the screen. You''ll see our sales performance for the past year. As you can see, we had a very strong start, but we hit a significant slump during the summer months due to the supply chain disruption. Fortunately, our holiday marketing campaign was a massive success, leading to our highest growth period at the end of the year. We hope to maintain this momentum into the next quarter.', '[{"text": "What caused a decline in sales?", "options": ["(A) High employee turnover", "(B) Supply chain issues", "(C) A failed advertisement", "(D) Competitor pricing"], "answer": "B"}, {"text": "Look at the graphic. Which quarter represents the \"summer slump\" mentioned by the speaker?", "options": ["(A) Q1", "(B) Q2", "(C) Q3", "(D) Q4"], "answer": "C"}, {"text": "What does the speaker credit for the year-end success?", "options": ["(A) A new product launch", "(B) A holiday campaign", "(C) A reduction in prices", "(D) An expansion into Europe"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk12.mp3', true, NULL),
  (20, 'Radio Advertisement', 'Are you looking to improve your professional skills? The City Evening College is now enrolling for the spring semester. We offer courses in everything from web design to project management. Classes are held twice a week starting at 7:00 PM, making it easy to study after work. Register by the end of this week to have your lab fees waived!', '[{"text": "Who is the target audience for this ad?", "options": ["(A) Full-time students", "(B) Retired teachers", "(C) Working professionals", "(D) High school children"], "answer": "C"}, {"text": "When do the classes take place?", "options": ["(A) On weekends", "(B) In the evenings", "(C) During the lunch hour", "(D) Early in the morning"], "answer": "B"}, {"text": "How can a student save money?", "options": ["(A) By enrolling in two classes", "(B) By paying in cash", "(C) By registering early", "(D) By bringing their own laptop"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk13.mp3', true, NULL),
  (21, 'Advertisement', 'Are you tired of paying high prices for your monthly cell phone plan? Switch to ClearCall Wireless! We offer unlimited talk and text for just $25 a month. Plus, if you bring your own device, we''ll give you a $50 credit on your first bill. Stop by any of our ten locations in the city today to make the switch.', '[{"text": "What is being advertised?", "options": ["(A) A new smartphone", "(B) A repair service", "(C) A mobile phone plan", "(D) An internet router"], "answer": "C"}, {"text": "What is the monthly cost of the service?", "options": ["(A) $10", "(B) $25", "(C) $50", "(D) $75"], "answer": "B"}, {"text": "How can a customer receive a $50 credit?", "options": ["(A) By referring a family member", "(B) By signing a two-year deal", "(C) By keeping their current phone", "(D) By visiting all ten locations"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk10.mp3', true, NULL),
  (22, 'Store Advertisement', 'Looking for a new laptop for college? Stop by ''TechHub'' this weekend for our annual student sale! We are offering 15% off all laptops and tablets. Plus, every purchase comes with a free wireless mouse and a one-year subscription to our antivirus software. Just show your valid student ID at the register to claim these savings.', '[{"text": "What is being advertised?", "options": ["(A) A university course", "(B) A software repair service", "(C) A computer sale", "(D) A wireless internet plan"], "answer": "C"}, {"text": "What item is given for free with a purchase?", "options": ["(A) A laptop bag", "(B) A wireless mouse", "(C) A set of headphones", "(D) A printer"], "answer": "B"}, {"text": "What must a customer provide to get a discount?", "options": ["(A) A coupon from a newspaper", "(B) A credit card", "(C) A student ID", "(D) An email address"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk24.mp3', true, NULL),
  (23, 'Instruction', 'Welcome to your first day at ''Prime Logistics.'' Your primary duty will be scanning incoming packages and sorting them by zip code. You must wear your high-visibility vest and steel-toed boots at all times while on the warehouse floor. If a package is marked ''Fragile,'' please place it on the separate blue conveyor belt for manual handling. Let''s get started with a tour of the facility.', '[{"text": "Where does this talk take place?", "options": ["(A) A retail store", "(B) A logistics warehouse", "(C) A post office", "(D) A construction site"], "answer": "B"}, {"text": "What is a task for the new employees?", "options": ["(A) Driving trucks", "(B) Cleaning floors", "(C) Sorting packages", "(D) Answering phones"], "answer": "C"}, {"text": "What should be done with ''Fragile'' items?", "options": ["(A) Put them in boxes", "(B) Use a specific belt", "(C) Call a supervisor", "(D) Leave them on the floor"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk30.mp3', true, NULL),
  (24, 'Tour Guide', 'Welcome to the National Space Museum. My name is David, and I''ll be your guide today. We will begin our tour in the Rocket Gallery, where you can see actual engines used in the Apollo missions. Please remember that flash photography is strictly prohibited as it can damage some of the older artifacts. We will end the tour at the gift shop in approximately one hour.', '[{"text": "Where is the tour taking place?", "options": ["(A) An art gallery", "(B) A space museum", "(C) A rocket factory", "(D) A history library"], "answer": "B"}, {"text": "What rule are the visitors asked to follow?", "options": ["(A) Do not touch the engines", "(B) Stay with the group", "(C) Do not use camera flashes", "(D) Keep their voices low"], "answer": "C"}, {"text": "How long will the tour last?", "options": ["(A) 30 minutes", "(B) 60 minutes", "(C) 90 minutes", "(D) Two hours"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk07.mp3', true, NULL),
  (25, 'Plant Safety Briefing', 'Before we begin the tour of the manufacturing floor, I must go over a few safety requirements. Everyone must wear a hard hat and safety goggles at all times. Also, please stay within the yellow painted lines on the floor; these are designated walking paths to keep you away from the automated machinery. If you hear a loud siren, please follow me to the nearest exit immediately.', '[{"text": "What is the speaker mainly discussing?", "options": ["(A) Machine maintenance", "(B) Hiring procedures", "(C) Safety regulations", "(D) Product quality"], "answer": "C"}, {"text": "What should visitors look for on the floor?", "options": ["(A) Fire extinguishers", "(B) Yellow lines", "(C) Emergency buttons", "(D) Tool boxes"], "answer": "B"}, {"text": "What should listeners do if they hear a siren?", "options": ["(A) Turn off the machines", "(B) Call for help", "(C) Put on their goggles", "(D) Exit the building"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk14.mp3', true, NULL),
  (26, 'Store Announcement', 'Attention shoppers, we would like to remind you that our customer loyalty program is changing. Starting next month, points will no longer expire at the end of the year. Instead, you can save them up for larger rewards, such as $50 gift cards. To update your account information, please visit the service desk located near the main entrance. Thank you for shopping with us.', '[{"text": "What is changing at the store?", "options": ["(A) The store hours", "(B) The return policy", "(C) The loyalty program", "(D) The store''s location"], "answer": "C"}, {"text": "What is a benefit of the new system?", "options": ["(A) Points do not expire", "(B) Double points on weekends", "(C) Lower prices for members", "(D) Free home delivery"], "answer": "A"}, {"text": "Where can customers update their accounts?", "options": ["(A) On the store website", "(B) At the checkout counter", "(C) At the service desk", "(D) Through a mobile app"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk20.mp3', true, NULL),
  (27, 'Product Introduction', 'I''m thrilled to introduce our newest kitchen appliance, the ''QuickChef 3000.'' This multi-cooker can steam, sauté, and pressure cook all in one device. It features a digital interface with over fifty pre-set recipes. Best of all, it uses 70% less energy than a conventional oven. It will be available in major retail stores starting next Tuesday.', '[{"text": "What is the ''QuickChef 3000''?", "options": ["(A) A dishwasher", "(B) A refrigerator", "(C) A multi-cooker", "(D) A microwave"], "answer": "C"}, {"text": "What is highlighted as a main benefit?", "options": ["(A) Its large size", "(B) Its low price", "(C) Its energy efficiency", "(D) Its colorful design"], "answer": "C"}, {"text": "When will the product go on sale?", "options": ["(A) Today", "(B) Tomorrow", "(C) This weekend", "(D) Next Tuesday"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk17.mp3', true, NULL),
  (28, 'Voicemail Message', 'Hello, this is Brenda from ''City Fitness.'' I''m calling to let you know that the yoga class you signed up for on Tuesday morning has been moved to Thursday at the same time. The instructor, Mr. Lee, has a family emergency. If you cannot attend the new session, please let us know and we will credit your account for a future class. We apologize for any inconvenience.', '[{"text": "Why is the class being rescheduled?", "options": ["(A) The gym is being renovated", "(B) There were not enough students", "(C) The teacher is unavailable", "(D) The building lost power"], "answer": "C"}, {"text": "When will the new class take place?", "options": ["(A) Tuesday evening", "(B) Wednesday morning", "(C) Thursday morning", "(D) Friday afternoon"], "answer": "C"}, {"text": "What does the speaker offer to those who cannot attend?", "options": ["(A) A cash refund", "(B) A credit for later use", "(C) A free water bottle", "(D) A private lesson"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk33.mp3', true, NULL),
  (29, 'Excerpt from a Meeting', 'Before we adjourn, I''d like to thank everyone for their hard work on the ''Aero-Tech'' project. Because we finished the design phase two weeks ahead of schedule, the board of directors has approved a bonus for the entire engineering team. You will see this reflected in your next paycheck. Now, let''s head to the cafeteria—the company is providing lunch to celebrate our success.', '[{"text": "What is the reason for the celebration?", "options": ["(A) A new CEO was hired", "(B) An early project completion", "(C) A high sales record", "(D) A company anniversary"], "answer": "B"}, {"text": "How will the employees be rewarded?", "options": ["(A) With extra vacation days", "(B) With new laptops", "(C) With a financial bonus", "(D) With a promotion"], "answer": "C"}, {"text": "What will the employees do next?", "options": ["(A) Start a new project", "(B) Go to the cafeteria", "(C) Go home early", "(D) Call the board of directors"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk39.mp3', true, NULL),
  (30, 'Weather Report', 'Good morning, listeners. It''s a beautiful start to the day with clear skies, but don''t let that fool you. A low-pressure system is moving in from the west. We expect light showers to start around lunchtime, but the heaviest rainfall will hit right during the evening commute. If you''re planning to walk home from work, you''ll definitely want to bring an umbrella for the late afternoon.', '[{"text": "How is the weather at the time of the broadcast?", "options": ["(A) Rainy", "(B) Clear", "(C) Snowy", "(D) Windy"], "answer": "B"}, {"text": "Look at the graphic. At what time is rain most likely to occur?", "options": ["(A) 10 AM", "(B) 1 PM", "(C) 4 PM", "(D) 7 PM"], "answer": "C"}, {"text": "What does the speaker suggest listeners do?", "options": ["(A) Leave work early", "(B) Drive instead of walk", "(C) Carry an umbrella", "(D) Wear a heavy coat"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk18.mp3', true, NULL),
  (31, 'Radio News Report', 'In local news, the ''Northside Bridge'' will be closed to all traffic starting at midnight this Friday. City engineers will be performing essential structural repairs that are expected to take forty-eight hours. Commuters who normally use the bridge to reach the downtown area are encouraged to take the subway or use the ferry service. The bridge is expected to reopen in time for the Monday morning rush hour.', '[{"text": "When will the bridge close?", "options": ["(A) Monday morning", "(B) Wednesday night", "(C) Friday midnight", "(D) Sunday afternoon"], "answer": "C"}, {"text": "Why is the bridge being closed?", "options": ["(A) A film is being shot", "(B) Structural maintenance", "(C) A marathon race", "(D) Severe weather"], "answer": "B"}, {"text": "What alternative does the speaker suggest?", "options": ["(A) Riding a bicycle", "(B) Taking a ferry", "(C) Working from home", "(D) Walking across the bridge"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk36.mp3', true, NULL),
  (32, 'Recorded Message', 'Thank you for calling the Grandview Cinema. Our box office is currently closed. To purchase tickets for today''s showings, please visit our website or use our mobile app. Note that we are offering a special discount for our 4:00 PM matinee of ''Mountain Peak''—all seats are half-price. Our concession stand now features organic popcorn and locally made sodas. Enjoy the show!', '[{"text": "What is the speaker''s main purpose?", "options": ["(A) To complain about a film", "(B) To provide theater information", "(C) To hire new ushers", "(D) To announce a movie cancellation"], "answer": "B"}, {"text": "How can a caller get a discount today?", "options": ["(A) By buying a large popcorn", "(B) By joining a loyalty club", "(C) By attending a specific time", "(D) By showing a student ID"], "answer": "C"}, {"text": "What is new at the concession stand?", "options": ["(A) Hot dogs", "(B) Ice cream", "(C) Candy bars", "(D) Organic snacks"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk31.mp3', true, NULL),
  (33, 'Advertisement', 'Don''t spend your weekend cleaning the house! Let ''Sparkle Services'' handle it for you. We provide professional cleaning for homes and offices. Our team uses only environmentally friendly products that are safe for pets and children. Call us by Wednesday to receive a $20 discount on your first deep-clean. Visit our website to read testimonials from our happy customers.', '[{"text": "What type of business is being advertised?", "options": ["(A) A pet store", "(B) A landscaping company", "(C) A cleaning service", "(D) A grocery delivery"], "answer": "C"}, {"text": "What is special about the products used?", "options": ["(A) They are very cheap", "(B) They are eco-friendly", "(C) They are imported from Europe", "(D) They smell like lemons"], "answer": "B"}, {"text": "How can a customer get a discount?", "options": ["(A) By booking on a weekend", "(B) By referring a neighbor", "(C) By calling early in the week", "(D) By signing up for a year"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk34.mp3', true, NULL),
  (34, 'Instruction', 'Welcome to the annual Small Business Expo. When you entered, you should have received a badge and a folder. Please keep your badge visible at all times for security reasons. We have a small change to the schedule printed in your folders. The workshop on marketing has been extended by thirty minutes, so the lunch break will start later than originally planned.', '[{"text": "What should attendees keep visible?", "options": ["(A) Their folders", "(B) Their identification badges", "(C) Their laptops", "(D) Their business cards"], "answer": "B"}, {"text": "What change does the speaker mention?", "options": ["(A) The venue has changed", "(B) A speaker is missing", "(C) An event will last longer", "(D) Lunch has been canceled"], "answer": "C"}, {"text": "Look at the graphic. According to the speaker, what time will the lunch likely begin now?", "options": ["(A) 11:30", "(B) 12:00", "(C) 1:00", "(D) 1:30"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk09.mp3', true, NULL),
  (35, 'News Report', 'This is Sarah Jenkins with your local news. Traffic is currently backed up on Route 12 due to a minor accident near the bridge. Drivers are advised to take the scenic bypass instead. Looking at our upcoming weather, the cold front arriving mid-week will bring some unexpected precipitation, so make sure you have your winter gear ready by the morning of the fourth day.', '[{"text": "Why is traffic slow on Route 12?", "options": ["(A) Road construction", "(B) A vehicle collision", "(C) Heavy rain", "(D) A bridge closure"], "answer": "B"}, {"text": "What does the speaker suggest drivers do?", "options": ["(A) Stay home", "(B) Drive slowly", "(C) Use an alternative route", "(D) Wait for the bridge to open"], "answer": "C"}, {"text": "Look at the graphic. What type of weather is expected on Thursday?", "options": ["(A) Sun", "(B) Rain", "(C) Wind", "(D) Snow"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk05.mp3', true, NULL),
  (36, 'Business Presentation', 'As we review our annual expenditures, you''ll notice a shift in where our capital is going. Last year, our biggest expense was physical equipment, but this year, our investment in cloud-based subscriptions has taken the top spot. We have successfully reduced our travel costs by using video conferencing. Moving forward, we aim to keep our smallest expense category—general office supplies—under 10% of the total budget.', '[{"text": "What was the company''s largest expense this year?", "options": ["(A) Computer hardware", "(B) Software subscriptions", "(C) Business travel", "(D) Office furniture"], "answer": "B"}, {"text": "Look at the graphic. Which category accounts for 20% of the spending?", "options": ["(A) Software", "(B) Hardware", "(C) Travel", "(D) Supplies"], "answer": "C"}, {"text": "How did the company reduce travel costs?", "options": ["(A) By flying economy class", "(B) By using video technology", "(C) By canceling all trips", "(D) By moving the office"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk32.mp3', true, NULL),
  (37, 'Weather Report', 'Good morning. We are tracking a major storm system that will move through the area today. While the morning will be relatively calm, the intensity will pick up significantly as the day progresses. We expect the most dangerous conditions to occur around sunset, when wind gusts could reach speeds high enough to knock down power lines. Conditions will settle down quite quickly after midnight.', '[{"text": "What is the main subject of the report?", "options": ["(A) A heatwave", "(B) A drought", "(C) A major storm", "(D) Heavy snowfall"], "answer": "C"}, {"text": "Look at the graphic. At what time will the wind be strongest?", "options": ["(A) 6 AM", "(B) 12 PM", "(C) 6 PM", "(D) 12 AM"], "answer": "C"}, {"text": "What does the speaker warn about?", "options": ["(A) Flooded roads", "(B) Falling power lines", "(C) Poor visibility", "(D) Extreme cold"], "answer": "B"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk38.mp3', true, NULL),
  (38, 'Recorded Message', 'You have reached the offices of Riverdale Medical. Our office is currently closed for the lunch hour. We will reopen at 1:30 PM. If you are calling to schedule an appointment, please press 1. If you have a prescription refill request, please call the pharmacy directly at 555-0199. For emergencies, please hang up and dial 911.', '[{"text": "Why is the office currently unavailable?", "options": ["(A) It is a holiday", "(B) It is the lunch break", "(C) It is undergoing repairs", "(D) It has moved locations"], "answer": "B"}, {"text": "What should a caller do to book a visit?", "options": ["(A) Press a button on the phone", "(B) Call back at 1:30 PM", "(C) Visit the office in person", "(D) Call the pharmacy"], "answer": "A"}, {"text": "What information is provided for prescription refills?", "options": ["(A) An email address", "(B) A doctor''s name", "(C) A website link", "(D) A phone number"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk06.mp3', true, NULL),
  (39, 'Instruction', 'Welcome to the ''Quality Electronics'' assembly line. Safety is our number one priority. Before you enter the cleanroom, you must put on a protective suit, a hairnet, and shoe covers. This prevents dust from damaging the microchips we are building. Also, please remember that no food or drinks are permitted in the work area. If you need a break, please use the designated lounge on the first floor.', '[{"text": "Where is this talk most likely occurring?", "options": ["(A) A restaurant kitchen", "(B) A clothing store", "(C) A computer factory", "(D) A hospital ward"], "answer": "C"}, {"text": "What is the purpose of the protective clothing?", "options": ["(A) To keep employees warm", "(B) To prevent contamination", "(C) To identify different teams", "(D) To protect against chemicals"], "answer": "B"}, {"text": "Where should employees go for a break?", "options": ["(A) The cleanroom", "(B) The parking lot", "(C) The first-floor lounge", "(D) The assembly line"], "answer": "C"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk37.mp3', true, NULL),
  (40, 'Public Service Announcement', 'The Department of Transportation would like to remind residents that the annual ''Bike to Work'' week begins this Monday. To encourage cycling, the city has installed temporary bike lanes on 5th Avenue and Broadway. Additionally, all city buses will be equipped with front-loading bike racks. Let''s work together to reduce traffic congestion and improve our air quality.', '[{"text": "What event is being announced?", "options": ["(A) A marathon", "(B) A cycling event", "(C) A car show", "(D) A street fair"], "answer": "B"}, {"text": "What change has been made to city buses?", "options": ["(A) Lower fares", "(B) New routes", "(C) Bike racks added", "(D) Electric engines"], "answer": "C"}, {"text": "What is a goal of this initiative?", "options": ["(A) To raise money for charity", "(B) To increase bus ridership", "(C) To promote tourism", "(D) To reduce traffic"], "answer": "D"}]', 'https://storage.googleapis.com/choppetonexam_toeic/toeic/part4/audio/talk16.mp3', true, NULL);
